INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('Heka', 'Adrastea', 'job_Adrasteia2.jpg', 'Heka raises her powers and prepares herself for battle.', 'Self Buff', '0 sec.', '20 sec.', '1.366 sec.', '490', 'Ancient Star Orb × 5', '[{"level":"Level 10","effects":["Duration: 300 seconds","A.R +1","Penetration +15","Evasion +20","All damage received -5%","Ignore monster immunity by 75","Damage additionally increases according to [Pathos]s type","[Pathos - I] 2x","[Pathos - II] 4x","[Pathos - III] 6x"]}]');
INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('Hektor', 'Salute', 'job_saluete.jpg', 'Before starting a battle, it promotes discipline. DEF will increase, and it instills a weakness to Melee attacks into the enemy.', 'Self-buff', '0 sec.', '20 sec.', '2 sec.', '100', 'Ancient Star Orb × 15', '[{"level":"Level 10","effects":["Duration : 300s","D.R. +1","ATK +10%","Monster ATK +500%","100% Chance to inflict [Bloody Salute] with normal attacks","Increased damage from Melee users while afflicted with [Bloody Salute]","(In case of [PC], Casting Time +20%)"]}]');
INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('Hellena', 'Memorise', 'job_memorise.jpg', 'Cuts the casting time for the next skill you use by re-routing arcane energies through more efficient channels.', 'Self-buff', '1.133 sec.', '60 sec.', '1.633 sec.', '300', 'Ancient Star Orb × 5', '[{"level":"Level 1","effects":["A.R. +1","Monster Damage +150%","Casting Time -22%","Cool time resets with 2% chance when the buff expires"]},{"level":"Level 10","effects":["A.R. +1","Monster Damage +150%","Casting Time -40%","Cool time resets with 20% chance when the buff expires"]},{"level":"Level 11","effects":["A.R. +1","Monster Damage +150%","Casting Time -42%","Cool time resets with 25% chance when the buff expires"]},{"level":"Level 12","effects":["A.R. +1","Monster Damage +150%","Casting Time -44%","Cool time resets with 30% chance when the buff expires"]},{"level":"Level 13","effects":["A.R. +1","Monster Damage +150%","Casting Time -46%","Cool time resets with 35% chance when the buff expires"]}]');
