INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('Heyran', 'Dagger Polish', 'job_daggerpolish.jpg', 'With a sharpened blade, every normal attack hit inflicts mortal wounds. HP of enemies with active [Enhanced Pierced Wound] decreases gradually in proportion to damage. 1/5 applies to PC.', 'Self-buff', '0 sec.', '50 sec.', '2.033 sec.', '300', 'Ancient Star Orb × 3', '[{"level":"Level 1","effects":["Duration 5 Minutes","Physical Penetration +1","Casts [Pierced Wound] by 100% as many as hits made with normal ATK","Every normal attack hit inflicts [Pierced Wound]. Skill attacks have 100% chance to change enemys [Pierced Wound] to [Enhanced Pierced Wound]"]},{"level":"Level 10","effects":["Duration 5 Minutes","Physical Penetration +10","Casts [Pierced Wound] by 100% as many as hits made with normal ATK","Every normal attack hit inflicts [Pierced Wound]. Skill attacks have 100% chance to change enemys [Pierced Wound] to [Enhanced Pierced Wound]"]},{"level":"Level 11","effects":["Duration 5 Minutes","Physical Penetration +11","A.R. +1","Casts [Pierced Wound] by 100% as many as hits made with normal ATK","Every normal attack hit inflicts [Pierced Wound]. Skill attacks have 100% chance to change enemys [Pierced Wound] to [Enhanced Pierced Wound]"]},{"level":"Level 12","effects":["Duration 5 Minutes","Physical Penetration +12","A.R. +1","Casts [Pierced Wound] by 100% as many as hits made with normal ATK","Every normal attack hit inflicts [Pierced Wound]. Skill attacks have 100% chance to change enemys [Pierced Wound] to [Enhanced Pierced Wound]"]},{"level":"Level 13","effects":["Duration 5 Minutes","Physical Penetration +13","A.R. +1","Casts [Pierced Wound] by 100% as many as hits made with normal ATK","Every normal attack hit inflicts [Pierced Wound]. Skill attacks have 100% chance to change enemys [Pierced Wound] to [Enhanced Pierced Wound]"]}]');
