INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('Hildegard', 'Menesis', 'clb_manicis.jpg', 'Intake holy aura into ones body to enhanced punching strength/nApplies [Inulnerable] upon successful hit against target with [Squashed Armor] Lv. 3', 'Self-Buff', '0 sec.', '50 sec.', '0.5 sec.', '600', 'Ancient Star Orb × 10', '[{"level":"Level 10","effects":["Duration: 300 seconds","D.R. +1","DEF +20","IMM +20","Ignores all damage except from normal attacks","Applies [Deviated Grace] upon successful skill hit","A.R.+1, ATK+25%","Monster ATK +300%","PEN +20","Normal Attack Damage increases in proportion to [INT]","[PvE Maps] The sanctuary will follow Hildegard","[PvP Maps] The sanctuary disappears when Hildegard is more than 12m away from it"]}]');
INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('IceMontoro', 'Deathless Body', 'job_deathlessbody.jpg', 'Increases DR. highly and ignores all attacks by turning into immortal status for a short time. (Except for some Invincible ignoring skills) But items cannot be used and SP becomes 0.', 'Self-buff', '0 sec.', '65 sec.', '0.2 sec.', '200', 'Ancient Star Orb × 4', '[{"level":"Level 10","effects":["Duration: 10s","SP is decreased to 10 continuously","Items cannot be used","Gear cannot be switched","During [Athanasia] stance, different effect activates","Applies [Immortal Spirit] Lv. 20"]}]');
