INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('Illusion', 'Show Time', 'job_showtime.jpg', 'Become the status that can maximize the ability by the cheers from lots of spectators.', 'Self-buff', '0 sec.', '20 sec.', '2 sec.', '300', 'Ancient Star Orb × 5', '[{"level":"Level 10","effects":["Duration : 300 sec.","[Show time!] buff level rises according to the number of players in the area (including yourself)","Increase in A.R., ATK, Penetration and Basic ATK Damage proportional to level","3 ~ 4 PCs : Lv.11","5 ~ 6 PCs : Lv.12","7 ~ 9 PCs : Lv.13","10 ~11 PCs : Lv.14","12 or more PCs : Lv.15","[PvE only] Skill damage increases by (4% of extra [STR])"]}]');
