INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('Ivelar', 'Situs', 'job_situs.jpg', 'Awakens to ones limits. Using the skill again raises the level.At level 3, re-using resets the stage and overlap.', 'Applies to oneself without target designation.', '0 sec.', '3 sec.', '2.033 sec.', 'Ancient Star Orb × 5', 'Ancient Star Orb × 15', '[{"level":"Level 10","effects":["Duration: 500 seconds","[Common]","Increases ATK against monsters by a total of [STR] * 0.1 / 0.2 / 0.3 (max +20% / +40% / +60%)","Increases Physical Penetration by a total of [STR] * 0.05 / 0.1 / 0.2 (max +10 / +20 / +40)","Consuming 200 SP per use of all attack skills.","If the SP to be consumed is less than the current SP, the skill will not hit.","[Level 2 Additional Effect]","Attack Rating +1","Movement Speed +5%","Movement Speed Limit +0.50","[Level 3 Additional Effect]","Attack Rating +1","Defense Rating +1","Movement Speed +10%","Movement Speed Limit +1.00","Removes SP consumption caused by [Situs]"]}]');
INSERT OR IGNORE INTO character_buffs (character_slug, buff_name, buff_image, description, target, casting_time, cooldown, duration, sp_cost, consume_item, levels) VALUES ('Ivy', 'Cooking Time', 'job_battlecook2.jpg', 'Fun cooking time! The effects change according to whether youre trimming the ingredients or roasting the meat.', 'None', '0 sec.', '30 sec.', '1.5333 sec.', '540', 'Ancient Star Orb × 10', '[{"level":"Level 10","effects":["Duration : 300 seconds","Changes to [Cooking Time - Knife] or [Cooking Time - Fire] according to the current stance.","Not applied during Bareknuckle."]}]');
